'use client';

import { useTrips } from '@/hooks/useTrips';
import { useState, useCallback, useMemo, useEffect, Suspense } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import {
  Briefcase,
  ChevronLeft,
  ChevronRight,
  ChevronDown,
  ChevronUp,
  Users,
  Calendar,
  Wallet,
  AlertTriangle,
  UserPlus,
  Search,
  Flag,
  ArrowUpDown,
  Download,
} from 'lucide-react';
import { useInboxTrips } from '@/hooks/useGovernance';
import { InlineError } from '@/components/error-boundary';
import { TripCard } from '@/components/inbox/TripCard';
import { ComposableFilterBar } from '@/components/inbox/ComposableFilterBar';
import { ViewProfileToggle } from '@/components/inbox/ViewProfileToggle';
import { InboxEmptyState } from '@/components/inbox/InboxEmptyState';
import { BackToOverviewLink } from '@/components/navigation/BackToOverviewLink';
import { deserializeFilters, serializeFilters, getSavedViewProfile, roleToViewProfile, viewProfileToRole } from '@/lib/inbox-helpers';
import type { ViewProfile } from '@/lib/inbox-helpers';
import type { InboxTrip, InboxFilters } from '@/types/governance';
type SortKey = 'priority' | 'destination' | 'value' | 'party' | 'dates' | 'sla';
type SortDirection = 'asc' | 'desc';

function leadCountLabel(count: number): string {
  return `${count} ${count === 1 ? 'lead' : 'leads'} total`;
}

const SORT_OPTIONS: Record<SortKey, { label: string; icon: React.ComponentType<{ className?: string }> }> = {
  priority: { label: 'Priority', icon: Flag },
  destination: { label: 'Destination', icon: Briefcase },
  value: { label: 'Value', icon: Wallet },
  party: { label: 'Party Size', icon: Users },
  dates: { label: 'Dates', icon: Calendar },
  sla: { label: 'SLA Status', icon: AlertTriangle },
};

// ============================================================================
// BULK ACTIONS TOOLBAR
// ============================================================================

function BulkActionsToolbar({
  selectedCount,
  onClearSelection,
  onAssign,
  onExport,
  agents,
}: {
  selectedCount: number;
  onClearSelection: () => void;
  onAssign: (agentId: string) => void;
  onExport: () => void;
  agents: { id: string; name: string }[];
}) {
  const [showAssignDropdown, setShowAssignDropdown] = useState(false);

  return (
    <div className='flex items-center justify-between py-2 px-3 bg-[#161b22] rounded-lg border border-[#30363d]'>
      <div className='flex items-center gap-3'>
        <span className='text-ui-sm text-[#e6edf3]'>
          <strong>{selectedCount}</strong> trips selected
        </span>
        <button
          onClick={onClearSelection}
          className='text-ui-xs text-[#8b949e] hover:text-[#e6edf3]'
        >
          Clear
        </button>
      </div>

      <div className='flex items-center gap-2'>
        <div className='relative'>
          <button
            onClick={() => setShowAssignDropdown(!showAssignDropdown)}
            className='flex items-center gap-1.5 px-3 py-1.5 bg-[#58a6ff] text-[#0d1117] rounded-lg text-ui-sm font-medium hover:bg-[#6eb5ff] transition-colors'
          >
            <UserPlus className='size-4' />
            Assign to…
          </button>

          {showAssignDropdown && (
            <div className='absolute top-full right-0 mt-1 w-48 bg-[#0f1115] border border-[#30363d] rounded-lg shadow-xl z-10'>
              {agents.map((agent) => (
                <button
                  key={agent.id}
                  onClick={() => {
                    onAssign(agent.id);
                    setShowAssignDropdown(false);
                  }}
                  className='w-full flex items-center gap-2 px-3 py-2 text-left text-ui-sm text-[#e6edf3] hover:bg-[#161b22] first:rounded-t-lg last:rounded-b-lg'
                >
                  <div className='size-6 rounded-full bg-[#58a6ff]/20 flex items-center justify-center text-[#58a6ff] text-ui-xs font-bold'>
                    {agent.name.split(' ').map(n => n[0]).join('')}
                  </div>
                  <div>{agent.name}</div>
                </button>
              ))}
            </div>
          )}
        </div>

        <button
          onClick={onExport}
          className='flex items-center gap-1.5 px-3 py-1.5 bg-[#161b22] text-[#8b949e] rounded-lg text-ui-sm hover:text-[#e6edf3] transition-colors'
        >
          <Download className='size-4' />
          Export
        </button>
      </div>
    </div>
  );
}

// ============================================================================
// MAIN PAGE
// ============================================================================

export default function InboxPage() {
  return (
    <Suspense fallback={<div className="p-6 text-[#8b949e]">Loading inbox…</div>}>
      <InboxPageWithSearchParams />
    </Suspense>
  );
}

function InboxPageWithSearchParams() {
  const { push } = useRouter();
  const searchParams = useSearchParams();
  const getSearchParam = searchParams.get.bind(searchParams);

  // URL Persistence Sync
  const sortBy = (getSearchParam('sort') as SortKey) || 'priority';
  const sortDirection = (getSearchParam('dir') as SortDirection) || 'desc';
  const searchQuery = getSearchParam('q') || '';
  const page = Math.max(1, Number.parseInt(getSearchParam('page') || '1', 10) || 1);
  const limit = Math.max(1, Number.parseInt(getSearchParam('limit') || '20', 10) || 20);

  // Composable filters from URL params
  const activeFilters = useMemo<InboxFilters>(
    () => deserializeFilters(searchParams.toString()),
    [searchParams],
  );

  const updateParams = useCallback((updates: Record<string, string | null>) => {
    const params = new URLSearchParams(searchParams.toString());
    Object.entries(updates).forEach((entry) => {
      const [key, value] = entry;
      if (value === null) params.delete(key);
      else params.set(key, value);
    });
    push(`?${params.toString()}`);
  }, [push, searchParams]);

  const [selectedTrips, setSelectedTrips] = useState<Set<string>>(new Set());
  const [showSortDropdown, setShowSortDropdown] = useState(false);

  // View profile from URL role param, falling back to localStorage, then default
  const [viewProfile, setViewProfile] = useState<ViewProfile>(() => {
    const fromUrl = getSearchParam('role');
    if (fromUrl) return roleToViewProfile(fromUrl);
    return getSavedViewProfile() ?? 'operations';
  });

  const handleViewProfileChange = useCallback((profile: ViewProfile) => {
    setViewProfile(profile);
    updateParams({ role: viewProfileToRole(profile) });
  }, [updateParams]);

  const {
    data: inboxTrips,
    total: inboxTotal,
    hasMore,
    isLoading,
    error,
    refetch,
    assignTrips,
  } = useInboxTrips(
    activeFilters,
    page,
    limit,
    sortBy,
    sortDirection,
    searchQuery
  );

  const agents = useMemo(() => {
    const seen = new Map<string, string>();
    for (const t of inboxTrips) {
      if (t.assignedTo && t.assignedToName && !seen.has(t.assignedTo)) {
        seen.set(t.assignedTo, t.assignedToName);
      }
    }
    return Array.from(seen.entries()).map((entry) => {
      const [id, name] = entry;
      return { id, name };
    });
  }, [inboxTrips]);

  // ============================================================================
  // FILTER HANDLING
  // ============================================================================

  const hasFilters = useMemo(() => {
    const f = activeFilters;
    return (
      (f.priority?.length ?? 0) > 0 ||
      (f.slaStatus?.length ?? 0) > 0 ||
      (f.stage?.length ?? 0) > 0 ||
      (f.assignedTo?.length ?? 0) > 0 ||
      f.minValue !== undefined ||
      f.maxValue !== undefined
    );
  }, [activeFilters]);

  const handleFiltersChange = useCallback((newFilters: InboxFilters) => {
    const params = new URLSearchParams();
    params.set('page', '1');
    params.set('limit', String(limit));
    if (sortBy) params.set('sort', sortBy);
    if (sortDirection) params.set('dir', sortDirection);
    if (searchQuery) params.set('q', searchQuery);

    // Serialize composable filters to URL params
    const filterString = serializeFilters(newFilters);
    const filterParams = new URLSearchParams(filterString);
    for (const [key, value] of filterParams) {
      params.set(key, value);
    }

    push(`?${params.toString()}`);
  }, [push, limit, sortBy, sortDirection, searchQuery]);

  // Server drives pagination. We trust the returned items are already
  // filtered/sorted/paged. Display them directly.
  const totalFiltered = inboxTotal;
  const totalPages = Math.max(1, Math.ceil(inboxTotal / limit));
  const currentPage = Math.min(page, totalPages);
  const hasNextPage = hasMore;

  useEffect(() => {
    if (page !== currentPage) {
      updateParams({ page: String(currentPage) });
    }
  }, [page, currentPage, updateParams]);

  const handleSelect = useCallback((id: string, selected: boolean) => {
    setSelectedTrips((prev) => {
      const next = new Set(prev);
      if (selected) {
        next.add(id);
      } else {
        next.delete(id);
      }
      return next;
    });
  }, []);

  const handleClearSelection = useCallback(() => {
    setSelectedTrips(new Set());
  }, []);

  const handleCardAssign = useCallback((tripId: string, agentId: string) => {
    assignTrips({ tripIds: [tripId], assignTo: agentId, notifyAssignee: true });
  }, [assignTrips]);

  const handleBulkAssign = useCallback((agentId: string) => {
      const tripIds = [...selectedTrips];
    handleClearSelection();
  }, [selectedTrips, handleClearSelection, assignTrips]);

  const handleExport = useCallback(() => {
    const selected = inboxTrips.filter((t) => selectedTrips.has(t.id));
    const csv = [
      'ID,Destination,Priority,SLA,Agent',
      ...selected.map((t) => `${t.id},${t.destination},${t.priority},${t.slaStatus},${t.assignedToName || 'Unassigned'}`),
    ].join('\n');
    const blob = new Blob([csv], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `inbox-export-${new Date().toISOString().slice(0, 10)}.csv`;
    a.click();
    URL.revokeObjectURL(url);
  }, [selectedTrips, inboxTrips]);

  if (error) {
    return (
      <div className='p-5 max-w-[1400px] mx-auto space-y-5'>
        <BackToOverviewLink />
        <div className='flex items-center justify-between pt-1'>
          <div>
            <h1 className='text-ui-xl font-semibold text-[#e6edf3]'>Lead Inbox</h1>
            <p className='text-ui-sm text-[#8b949e] mt-0.5'>New customer inquiries sorted by urgency.</p>
          </div>
        </div>
        <div className='rounded-xl border border-[#1c2128] bg-[#0f1115] p-8 text-center'>
          <InlineError message='Failed to load inbox' />
          <button
            type='button'
            onClick={() => refetch()}
            className='mt-4 px-4 py-2 bg-[#58a6ff] text-[#0d1117] rounded-lg text-ui-sm font-medium hover:bg-[#6eb5ff] transition-colors'
          >
            Retry
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className='p-5 pb-4 max-w-[1400px] mx-auto space-y-5'>
      <BackToOverviewLink />
      {/* Header */}
      <header className='flex items-center justify-between pt-1'>
        <div>
          <h1 className='text-ui-xl font-semibold text-[#e6edf3]'>Lead Inbox</h1>
          <p className='text-ui-sm text-[#8b949e] mt-0.5'>New customer inquiries sorted by urgency.</p>
        </div>

        <div className='flex items-center gap-3 flex-wrap'>
          <div className='relative flex-1 min-w-[180px] max-w-64'>
            <Search className='absolute left-3 top-1/2 -translate-y-1/2 size-4 text-[#8b949e]' />
            <input
              type='text'
              placeholder='Search by customer, destination, or lead ref…'
              value={searchQuery}
              onChange={(e) => updateParams({ q: e.target.value || null, page: '1' })}
              className='w-full pl-9 pr-3 py-2 bg-[#161b22] border border-[#30363d] rounded-lg text-ui-sm text-[#e6edf3] placeholder-[#484f58] focus:outline-none focus:border-[#58a6ff]'
            />
          </div>

          <div className='relative'>
            <button
              onClick={() => setShowSortDropdown(!showSortDropdown)}
              className='flex items-center gap-2 px-3 py-2 bg-[#161b22] border border-[#30363d] rounded-lg text-ui-sm text-[#e6edf3] hover:border-[#484f58] transition-colors'
            >
              <ArrowUpDown className='size-4 text-[#8b949e]' />
              <span>Sort by {SORT_OPTIONS[sortBy].label}</span>
              {sortDirection === 'asc' ? (
                <ChevronUp className='size-4 text-[#8b949e]' />
              ) : (
                <ChevronDown className='size-4 text-[#8b949e]' />
              )}
            </button>

            {showSortDropdown && (
              <div className='absolute top-full right-0 mt-1 w-56 bg-[#0f1115] border border-[#30363d] rounded-lg shadow-xl z-10'>
                <div className='p-2 border-b border-[#30363d]'>
                  <div className='flex items-center justify-between px-2 py-1'>
                    <span className='text-ui-xs text-[#8b949e] font-medium'>Direction</span>
                    <div className='flex items-center gap-1'>
                      <button
                        onClick={() => updateParams({ dir: 'asc', page: '1' })}
                        className={`p-1 rounded transition-colors ${
                          sortDirection === 'asc'
                            ? 'bg-[#58a6ff] text-[#0d1117]'
                            : 'text-[#8b949e] hover:text-[#e6edf3]'
                        }`}
                      >
                        <ChevronUp className='size-4' />
                      </button>
                      <button
                        onClick={() => updateParams({ dir: 'desc', page: '1' })}
                        className={`p-1 rounded transition-colors ${
                          sortDirection === 'desc'
                            ? 'bg-[#58a6ff] text-[#0d1117]'
                            : 'text-[#8b949e] hover:text-[#e6edf3]'
                        }`}
                      >
                        <ChevronDown className='size-4' />
                      </button>
                    </div>
                  </div>
                </div>
                <div className='p-1'>
                  {(Object.keys(SORT_OPTIONS) as SortKey[]).map((key) => {
                    const option = SORT_OPTIONS[key];
                    const Icon = option.icon;
                    return (
                      <button
                        key={key}
                        onClick={() => {
                          updateParams({ sort: key, page: '1' });
                          setShowSortDropdown(false);
                        }}
                        className={`w-full flex items-center gap-2 px-3 py-2 text-left text-ui-sm rounded-md transition-colors ${
                          sortBy === key
                            ? 'bg-[#58a6ff] text-[#0d1117]'
                            : 'text-[#e6edf3] hover:bg-[#161b22]'
                        }`}
                      >
                        <Icon className='size-4' />
                        <span>{option.label}</span>
                      </button>
                    );
                  })}
                </div>
              </div>
            )}
          </div>

          <ViewProfileToggle
            current={viewProfile}
            onChange={handleViewProfileChange}
          />

          <span className='text-ui-sm text-[#8b949e]'>
          <span className="text-ui-sm text-[#8b949e]">
          {isLoading ? 'Loading…' : leadCountLabel(inboxTotal)}
        </span>
          </span>
          <div className='flex items-center gap-2'>
            <label htmlFor='inbox-limit' className='text-ui-xs text-[#8b949e]'>Rows</label>
            <select
              id='inbox-limit'
              value={String(limit)}
              onChange={(e) => updateParams({ limit: e.target.value, page: '1' })}
              className='bg-[#161b22] border border-[#30363d] rounded-md px-2 py-1 text-ui-xs text-[#e6edf3] focus:outline-none focus:border-[#58a6ff]'
            >
              <option value='10'>10</option>
              <option value='20'>20</option>
              <option value='30'>30</option>
              <option value='50'>50</option>
            </select>
          </div>
        </div>
      </header>

      {/* Bulk Actions Toolbar */}
      {selectedTrips.size > 0 && (
        <BulkActionsToolbar
          selectedCount={selectedTrips.size}
          onClearSelection={handleClearSelection}
          onAssign={handleBulkAssign}
          onExport={handleExport}
          agents={agents}
        />
      )}

      {/* Filters */}
      <ComposableFilterBar
        filters={activeFilters}
        onFiltersChange={handleFiltersChange}
        total={inboxTotal}
      />
      {!!searchQuery && (
        <div className='flex items-center justify-end'>
          <button
            type='button'
            onClick={() => updateParams({ q: null, page: '1' })}
            className='text-ui-xs text-[#8b949e] hover:text-[#e6edf3] underline underline-offset-2'
          >
            Clear search
          </button>
        </div>
      )}

      {/* Trip Grid */}
      {isLoading && inboxTrips.length === 0 ? (
        <div className='grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-3'>
          {['inbox-skeleton-1', 'inbox-skeleton-2', 'inbox-skeleton-3', 'inbox-skeleton-4', 'inbox-skeleton-5', 'inbox-skeleton-6'].map((skeletonKey) => (
            <div
              key={skeletonKey}
              className='rounded-xl border border-[#1c2128] bg-[#0f1115] p-4 space-y-3'
            >
              <div className='h-4 bg-[#161b22] rounded w-1/2' />
              <div className='h-3 bg-[#161b22] rounded w-1/3' />
              <div className='h-3 bg-[#161b22] rounded w-2/3' />
            </div>
          ))}
        </div>
      ) : (
        <div className='grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-3'>
          {inboxTrips.map((trip) => (
            <TripCard
              key={trip.id}
              trip={trip}
              isSelected={selectedTrips.has(trip.id)}
              onSelect={handleSelect}
              onAssign={handleCardAssign}
              agents={agents}
              viewProfile={viewProfile}
            />
          ))}
          {inboxTrips.length === 0 && !isLoading && (
            <InboxEmptyState
              hasSearch={!!searchQuery}
              hasFilters={hasFilters}
              onClearSearch={() => updateParams({ q: null, page: '1' })}
              onClearAllFilters={() => handleFiltersChange({})}
            />
          )}
        </div>
      )}

      <div className='flex items-center justify-between pt-1'>
        <p className='text-ui-xs text-[#8b949e]'>
          Page {currentPage} of {totalPages} · {totalFiltered} shown · {inboxTotal} total leads
        </p>
        <div className='flex items-center gap-2'>
          <button
            type='button'
            onClick={() => updateParams({ page: String(Math.max(1, currentPage - 1)) })}
            disabled={currentPage <= 1}
            className='inline-flex items-center gap-1.5 px-3 py-1.5 rounded-lg border border-[#30363d] text-ui-xs text-[#e6edf3] disabled:opacity-50 disabled:cursor-not-allowed hover:border-[#484f58] transition-colors'
          >
            <ChevronLeft className='size-3.5' />
            Prev
          </button>
          <button
            type='button'
            onClick={() => updateParams({ page: String(currentPage + 1) })}
            disabled={!hasNextPage}
            className='inline-flex items-center gap-1.5 px-3 py-1.5 rounded-lg border border-[#30363d] text-ui-xs text-[#e6edf3] disabled:opacity-50 disabled:cursor-not-allowed hover:border-[#484f58] transition-colors'
          >
            Next
            <ChevronRight className='size-3.5' />
          </button>
        </div>
      </div>
    </div>
  );
}

'use client';

import Link from 'next/link';
import { useRouter, useSearchParams } from 'next/navigation';
import { Suspense, memo, useMemo, useState } from 'react';
import {
  ArrowRight,
  AlertTriangle,
  Activity,
  ChevronRight,
  Send,
  MapPin,
} from 'lucide-react';
import { getTripRoute } from '@/lib/routes';
import { InlineError } from '@/components/error-boundary';
import { PlanningTripCard } from '@/components/workspace/PlanningTripCard';
import type { Trip } from '@/lib/api-client';
import {
  formatBudgetDisplay,
  formatInquiryReference,
} from '@/lib/lead-display';
import {
  getPlanningHeaderTitle,
  getPlanningIdentityLine,
  getPlanningNextAction,
  getPlanningRecencyLabel,
  getPlanningStatusLabel,
  getPlanningSummaryText,
  getPlanningStatusTone,
} from '@/lib/planning-status';
import { useOverviewSummary } from './useOverviewSummary';
import { EmptyStateOnboarding } from '@/components/overview/EmptyStateOnboarding';
import SystemCheckPanel from '@/components/system/SystemCheckPanel';

// ── Severity grammar: color encodes state, not decoration ──────────────────

type StateKey = 'green' | 'amber' | 'red' | 'blue';

interface StateMeta {
  fg: string;
  bg: string;
  border: string;
  label: string;
}

const STATE_META: Record<StateKey, StateMeta> = {
  green: {
    fg: '#3fb950',
    bg: 'rgba(63,185,80,0.10)',
    border: 'rgba(63,185,80,0.25)',
    label: 'Ready for Booking',
  },
  amber: {
    fg: '#d29922',
    bg: 'rgba(210,153,34,0.10)',
    border: 'rgba(210,153,34,0.25)',
    label: 'Need Trip Options',
  },
  red: {
    fg: '#f85149',
    bg: 'rgba(248,81,73,0.10)',
    border: 'rgba(248,81,73,0.25)',
    label: 'Needs Quote Review',
  },
  blue: {
    fg: '#58a6ff',
    bg: 'rgba(88,166,255,0.10)',
    border: 'rgba(88,166,255,0.25)',
    label: 'Need Customer Details',
  },
};

const INTAKE_HREF = '/workbench?draft=new&tab=intake';

function formatPlanningStageLabel(label: string): string {
  const normalized = label.trim().toLowerCase().replace(/\s+/g, '_');

  switch (normalized) {
    case 'assigned':
      return 'Waiting for options';
    case 'in_progress':
      return 'Planning in progress';
    case 'ready_to_quote':
      return 'Ready for quote review';
    case 'ready_to_book':
      return 'Ready for booking';
    case 'blocked':
      return 'Needs attention';
    default:
      return label;
  }
}

function getAssignmentLabel(trip: Trip): string {
  if (trip.status === 'completed') return 'Completed';
  if (trip.status === 'in_progress') return 'In progress';
  return 'In planning';
}

// ── StatCard: metric-first operational instrument ─────────────────────────

const StatCard = memo(function StatCard({
  title,
  value,
  sub,
  ctaLabel,
  icon: Icon,
  state,
  isLoading,
  error,
  href,
}: {
  title: string;
  value: string | number;
  sub: string;
  ctaLabel: string;
  icon: React.FC<{ className?: string; style?: React.CSSProperties }>;
  state: StateKey;
  isLoading?: boolean;
  error?: Error | null;
  href?: string;
}) {
  const meta = STATE_META[state];

  if (error) {
    return (
      <div
        className='relative rounded-xl border p-4 flex flex-col gap-3'
        style={{
          background: 'var(--bg-surface)',
          borderColor: 'var(--border-default)',
          boxShadow: 'inset 0 0 0 1px rgba(248, 81, 73, 0.24)',
        }}
      >
        <div className='flex items-center justify-between'>
          <span className='text-[12px] font-semibold uppercase tracking-wider' style={{ color: 'var(--text-tertiary)' }}>{title}</span>
          <AlertTriangle className='size-4' style={{ color: 'var(--accent-red)' }} />
        </div>
        <span className='text-[13px] font-medium' style={{ color: 'var(--accent-red)' }}>Failed to load</span>
      </div>
    );
  }

  const displayValue = isLoading && value === '-' ? '-' : value;
  const displaySub = isLoading && sub === 'Loading…' ? 'Loading…' : sub;

  const cardContent = (
    <>
      {/* Row: label + icon badge */}
      <div className='flex items-center justify-between'>
        <span className='text-[12px] font-semibold uppercase tracking-wider' style={{ color: 'var(--text-tertiary)' }}>{title}</span>
        <div
          className='size-7 rounded-md flex items-center justify-center'
          style={{ background: meta.bg, border: `1px solid ${meta.border}` }}
        >
          <Icon className='size-3.5' style={{ color: meta.fg }} />
        </div>
      </div>
      {/* Metric value - the anchor */}
      <span
        className='text-[24px] font-bold tabular-nums leading-none'
        style={{ color: displayValue === '-' ? 'var(--text-muted)' : meta.fg }}
      >
        {displayValue}
      </span>
      {/* Subtext - tertiary */}
      <span className='text-[12px] font-medium' style={{ color: 'var(--text-muted)' }}>{displaySub}</span>
      {href && (
        <div className='flex items-center gap-1 mt-0.5 text-[12px] font-medium' style={{ color: 'var(--accent-blue)' }}>
          {ctaLabel} <ArrowRight className='size-3' style={{ color: 'var(--accent-blue)' }} />
        </div>
      )}
    </>
  );

  const cardStyles: React.CSSProperties = {
    background: 'var(--bg-surface)',
    borderColor: 'var(--border-default)',
    borderTop: `2px solid ${meta.fg}`,
  };

  const cardClassName = 'relative rounded-xl border p-4 flex flex-col gap-2.5 transition-colors cursor-pointer';

  if (href) {
    return (
      <Link
        href={href}
        className={cardClassName}
        style={cardStyles}
        onMouseEnter={(e) => {
          const el = e.currentTarget as HTMLAnchorElement;
          Object.assign(el.style, { borderColor: 'var(--border-hover)', background: 'var(--bg-elevated)' });
        }}
        onMouseLeave={(e) => {
          const el = e.currentTarget as HTMLAnchorElement;
          Object.assign(el.style, { borderColor: 'var(--border-default)', background: 'var(--bg-surface)' });
        }}
      >
        {cardContent}
      </Link>
    );
  }

  return (
    <div
      className={cardClassName}
      style={cardStyles}
      onMouseEnter={(e) => {
        const el = e.currentTarget as HTMLDivElement;
        Object.assign(el.style, { borderColor: 'var(--border-hover)', background: 'var(--bg-elevated)' });
      }}
      onMouseLeave={(e) => {
        const el = e.currentTarget as HTMLDivElement;
        Object.assign(el.style, { borderColor: 'var(--border-default)', background: 'var(--bg-surface)' });
      }}
    >
      {cardContent}
    </div>
  );
});

// ── PipelineBar: compact operational progress module ──────────────────────

const PipelineBar = memo(function PipelineBar({
  data,
  isLoading,
  error,
  leadInboxTotal,
  planningTripsTotal,
}: {
  data: Array<{ label: string; count: number }> | null;
  isLoading: boolean;
  error: Error | null;
  leadInboxTotal: number;
  planningTripsTotal: number;
}) {
  const safeData = data ?? [];
  const stageTotal = useMemo(() => {
    return safeData.reduce((s, x) => s + (Number(x.count) || 0), 0);
  }, [safeData]);
  const total = planningTripsTotal;

  const [isExpanded, setIsExpanded] = useState(false);

  if (error) {
    return (
      <div className='rounded-xl border p-4' style={{ background: 'var(--bg-surface)', borderColor: 'var(--border-default)', boxShadow: 'inset 0 0 0 1px rgba(248, 81, 73, 0.24)' }}>
        <InlineError message='Failed to load pipeline data' />
      </div>
    );
  }

  if (isLoading && safeData.length === 0) {
    return (
      <div className='rounded-xl border p-4' style={{ background: 'var(--bg-surface)', borderColor: 'var(--border-default)' }}>
        <div className='flex items-center justify-between mb-3'>
          <h2 className='text-[12px] font-semibold uppercase tracking-wider' style={{ color: 'var(--text-tertiary)' }}>Planning Progress</h2>
          <span className='text-[12px] font-mono' style={{ color: 'var(--text-tertiary)' }}>Loading…</span>
        </div>
        <div className='h-2 rounded-full overflow-hidden' style={{ background: 'var(--bg-elevated)' }}>
          <div className='h-full' style={{ width: '30%', background: 'var(--accent-blue)' }} />
        </div>
      </div>
    );
  }

  if (safeData.length === 0 || stageTotal === 0 || total === 0) {
    const hasLeadsWaiting = leadInboxTotal > 0;
    return (
      <div className='rounded-xl border p-4' style={{ background: 'var(--bg-surface)', borderColor: 'var(--border-default)' }}>
        <div className='flex items-center justify-between mb-1'>
          <h2 className='text-[12px] font-semibold uppercase tracking-wider' style={{ color: 'var(--text-tertiary)' }}>Planning Progress</h2>
          <span className='text-[13px] font-mono font-medium tabular-nums' style={{ color: 'var(--text-primary)' }}>0</span>
        </div>
        <p className='text-[12px]' style={{ color: 'var(--text-muted)' }}>
          {hasLeadsWaiting
            ? 'A lead is waiting in Lead Inbox and needs review before planning can begin.'
            : 'No trips are being planned yet.'}
        </p>
        <Link
          href={hasLeadsWaiting ? '/inbox' : INTAKE_HREF}
          className='inline-flex items-center gap-1.5 mt-3 text-[12px] font-medium transition-colors'
          style={{ color: 'var(--accent-blue)' }}
        >
          {hasLeadsWaiting ? 'Review Lead' : 'Process New Inquiry'} <ArrowRight className='size-3.5' />
        </Link>
      </div>
    );
  }

  // Collapsed: summary bar
  if (!isExpanded) {
    const topStage = safeData.reduce((maxStage, stage) =>
      stage.count > maxStage.count ? stage : maxStage
    );

    return (
      <div className='rounded-xl border p-4' style={{ background: 'var(--bg-surface)', borderColor: 'var(--border-default)' }}>
        <div className='flex items-center justify-between mb-2'>
          <h2 className='text-[12px] font-semibold uppercase tracking-wider' style={{ color: 'var(--text-tertiary)' }}>Planning Progress</h2>
          <button
            onClick={() => setIsExpanded(true)}
            className='text-[12px] font-medium transition-colors'
            style={{ color: 'var(--accent-blue)' }}
          >
            Expand
          </button>
        </div>
        <div className='flex items-center gap-3'>
          <div className='flex-1'>
            <div className='h-2 rounded-full overflow-hidden flex' style={{ background: 'var(--bg-elevated)' }}>
              {safeData.map((stage, i) => (
                <div
                  key={stage.label || `stage-${i}`}
                  className='h-full transition-all'
                  style={{
                    width: `${(stage.count / stageTotal) * 100}%`,
                    background: ['#3fb950', '#58a6ff', '#d29922', '#f85149', '#a371f7'][i % 5],
                  }}
                />
              ))}
            </div>
          </div>
          <span className='text-[13px] font-semibold tabular-nums' style={{ color: 'var(--text-primary)' }}>{total}</span>
        </div>
        <p className='text-[12px] mt-1.5' style={{ color: 'var(--text-muted)' }}>
          {getPlanningSummaryText(topStage.label, total)}
        </p>
      </div>
    );
  }

  // Expanded: vertical stage list
  return (
    <div className='rounded-xl border p-4' style={{ background: 'var(--bg-surface)', borderColor: 'var(--border-default)' }}>
      <div className='flex items-center justify-between mb-3'>
        <h2 className='text-[12px] font-semibold uppercase tracking-wider' style={{ color: 'var(--text-tertiary)' }}>Planning Progress</h2>
        <div className='flex items-center gap-2'>
          <span className='text-[12px] font-mono tabular-nums' style={{ color: 'var(--text-tertiary)' }}>{total} total</span>
          <button
            onClick={() => setIsExpanded(false)}
            className='text-[12px] font-medium transition-colors'
            style={{ color: 'var(--text-muted)' }}
          >
            Collapse
          </button>
        </div>
      </div>

      <div className='space-y-2'>
        {safeData.map((stage, i) => {
          const pct = stageTotal > 0 ? (stage.count / stageTotal) * 100 : 0;
          const color = ['#3fb950', '#58a6ff', '#d29922', '#f85149', '#a371f7'][i % 5];
          return (
            <div key={stage.label} className='group'>
              <div className='flex items-center justify-between mb-1'>
                <span className='text-[12px] font-medium' style={{ color: 'var(--text-primary)' }}>
                  {formatPlanningStageLabel(stage.label)}
                </span>
                <span className='text-[12px] font-mono tabular-nums' style={{ color: 'var(--text-tertiary)' }}>{stage.count}</span>
              </div>
              <div className='h-1.5 rounded-full overflow-hidden' style={{ background: 'var(--bg-elevated)' }}>
                <div
                  className='h-full rounded-full transition-all'
                  style={{ width: `${pct}%`, background: color }}
                />
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
});

