// ── RecentTrips: empty + populated states ─────────────────────────────────

function RecentTrips({
  trips,
  isLoading,
  error,
  planningTripsTotal,
  leadInboxTotal,
}: {
  trips: Trip[];
  isLoading: boolean;
  error: Error | null;
  planningTripsTotal: number;
  leadInboxTotal: number;
}) {
  const hasLeadsWaiting = planningTripsTotal === 0 && leadInboxTotal > 0;

  if (error) {
    return (
      <div className='p-4'>
        <InlineError message='Failed to load recent trips' />
      </div>
    );
  }

  if (isLoading && trips.length === 0) {
    return (
      <div className='p-4 space-y-2'>
        {['overview-skeleton-1', 'overview-skeleton-2', 'overview-skeleton-3'].map((skeletonKey) => (
          <div key={skeletonKey} className='h-14 rounded-lg animate-pulse' style={{ background: 'var(--bg-elevated)' }} />
        ))}
      </div>
    );
  }

  if (trips.length === 0) {
    // First-run: no trips and no leads → full onboarding checklist
    if (!hasLeadsWaiting && planningTripsTotal === 0) {
      return <EmptyStateOnboarding />;
    }

    // Leads exist but no trips yet → simpler prompt to review the lead
    return (
      <div className='p-8 text-center'>
        <div
          className='size-14 rounded-xl flex items-center justify-center mx-auto mb-4'
          style={{
            background: 'var(--bg-elevated)',
            border: '1px solid var(--border-default)',
          }}
        >
          <MapPin className='size-6' style={{ color: 'var(--text-tertiary)' }} />
        </div>
        <p className='text-[14px] font-medium mb-1' style={{ color: 'var(--text-primary)' }}>
          No trips in planning yet
        </p>
        <p className='text-[12px] leading-relaxed max-w-[280px] mx-auto' style={{ color: 'var(--text-secondary)' }}>
          A lead is waiting in Lead Inbox. Review it to start planning, and the trip will appear here.
        </p>
        <Link
          href='/inbox'
          className='inline-flex items-center gap-2 mt-5 px-4 py-2 rounded-lg text-[13px] font-medium transition-colors border'
          style={{
            background: 'transparent',
            color: 'var(--text-primary)',
            borderColor: 'var(--border-default)',
          }}
          onMouseEnter={(e) => {
            const el = e.currentTarget as HTMLAnchorElement;
            Object.assign(el.style, { borderColor: 'var(--border-hover)', background: 'var(--bg-elevated)' });
          }}
          onMouseLeave={(e) => {
            const el = e.currentTarget as HTMLAnchorElement;
            Object.assign(el.style, { borderColor: 'var(--border-default)', background: 'transparent' });
          }}
        >
          <Send className='size-4' style={{ color: 'var(--accent-blue)' }} />
          Review Lead
          <ArrowRight className='size-3.5' style={{ color: 'var(--text-muted)' }} />
        </Link>
      </div>
    );
  }

  return (
    <div className='p-4'>
      <div className='grid grid-cols-1 gap-4'>
        {trips.map((trip) => (
          <PlanningTripCard key={trip.id} trip={trip} variant='overview' />
        ))}
      </div>
    </div>
  );
}

