'use client';

import { useEffect, useRef } from 'react';
import { X } from 'lucide-react';
import { cn } from '@/lib/utils';

export interface ModalProps {
  isOpen: boolean;
  onClose: () => void;
  title?: string;
  description?: string;
  children: React.ReactNode;
  footer?: React.ReactNode;
  size?: 'sm' | 'md' | 'lg';
  closeOnOverlay?: boolean;
}

export function Modal({
  isOpen,
  onClose,
  title,
  description,
  children,
  footer,
  size = 'md',
  closeOnOverlay = true,
}: ModalProps) {
  const dialogRef = useRef<HTMLDivElement>(null);
  const previousActiveElement = useRef<Element | null>(null);

  const sizeClasses = {
    sm: 'max-w-sm',
    md: 'max-w-lg',
    lg: 'max-w-2xl',
  };

  const onCloseRef = useRef(onClose);
  onCloseRef.current = onClose;

  useEffect(() => {
    if (!isOpen) return;

    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        onCloseRef.current();
        return;
      }

      if (e.key === 'Tab' && dialogRef.current) {
        const focusable = dialogRef.current.querySelectorAll<HTMLElement>(
          'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'
        );
        if (focusable.length === 0) return;

        const first = focusable[0];
        const last = focusable[focusable.length - 1];

        if (e.shiftKey) {
          if (document.activeElement === first) {
            e.preventDefault();
            last.focus();
          }
        } else {
          if (document.activeElement === last) {
            e.preventDefault();
            first.focus();
          }
        }
      }
    };

    previousActiveElement.current = document.activeElement;
    document.body.style.overflow = 'hidden';
    document.addEventListener('keydown', handleKeyDown);

    requestAnimationFrame(() => {
      const firstFocusable = dialogRef.current?.querySelector<HTMLElement>(
        'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'
      );
      firstFocusable?.focus();
    });

    return () => {
      document.body.style.overflow = '';
      document.removeEventListener('keydown', handleKeyDown);
      if (previousActiveElement.current instanceof HTMLElement) {
        previousActiveElement.current.focus();
      }
    };
  }, [isOpen]);

  if (!isOpen) return null;

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center"
      role="presentation"
    >
      <div
        className="absolute inset-0 bg-black/50"
        onClick={closeOnOverlay ? onClose : undefined}
        aria-hidden="true"
      />
      <div
        ref={dialogRef}
        role="dialog"
        aria-modal="true"
        aria-label={title}
        aria-describedby={description ? 'modal-description' : undefined}
        className={cn(
          'relative w-full mx-4 bg-[#0d1117] border border-[#30363d] rounded-2xl shadow-2xl flex flex-col max-h-[85vh]',
          sizeClasses[size]
        )}
      >
        {title && (
          <div className="flex items-center justify-between p-6 border-b border-[#30363d] shrink-0">
            <div className="min-w-0">
              <h2 className="text-ui-lg font-semibold text-[#e6edf3] truncate">
                {title}
              </h2>
              {description && (
                <p id="modal-description" className="text-ui-sm text-[#8b949e] mt-1">
                  {description}
                </p>
              )}
            </div>
            <button
              onClick={onClose}
              className="p-2 hover:bg-[#161b22] rounded-lg transition-colors ml-4 shrink-0"
              aria-label="Close modal"
            >
              <X className="size-5 text-[#8b949e]" />
            </button>
          </div>
        )}

        <div className="p-6 overflow-y-auto">
          {children}
        </div>

        {footer && (
          <div className="p-6 pt-0 shrink-0">
            {footer}
          </div>
        )}
      </div>
    </div>
  );
}

'use client';

import { cn } from '@/lib/utils';
import { useState, useRef, useEffect, useCallback } from 'react';

interface TabsProps {
  tabs: readonly { readonly id: string; readonly label: string; count?: number }[];
  activeTab: string;
  onTabChange: (tabId: string) => void;
  ariaLabel?: string;
}

const TAB_ID_PREFIX = 'wt-tab';
const PANEL_ID_PREFIX = 'wt-panel';

export function getTabButtonId(tabId: string): string {
  return `${TAB_ID_PREFIX}-${tabId}`;
}

export function getTabPanelId(tabId: string): string {
  return `${PANEL_ID_PREFIX}-${tabId}`;
}

export function Tabs({ tabs, activeTab, onTabChange, ariaLabel = 'Tab navigation' }: TabsProps) {
  const getTabLabel = (tabId: string) => tabs.find(t => t.id === tabId)?.label || tabId;

  const [announcement, setAnnouncement] = useState(() => `${getTabLabel(activeTab)} tab selected`);
  const prevTabRef = useRef(activeTab);

  useEffect(() => {
    if (prevTabRef.current !== activeTab) {
      setAnnouncement(`${getTabLabel(activeTab)} tab selected`);
      prevTabRef.current = activeTab;
    }
  }, [activeTab, tabs, getTabLabel]);

  const handleKeyDown = (e: React.KeyboardEvent<HTMLDivElement>) => {
    const tabElements = Array.from(
      e.currentTarget.querySelectorAll('[role="tab"]')
    ) as HTMLButtonElement[];
    const currentIndex = tabElements.findIndex(
      (tab) => tab.getAttribute('aria-selected') === 'true'
    );
    if (currentIndex === -1) return;

    let nextIndex = currentIndex;
    switch (e.key) {
      case 'ArrowLeft':
        nextIndex = currentIndex > 0 ? currentIndex - 1 : tabElements.length - 1;
        break;
      case 'ArrowRight':
        nextIndex = currentIndex < tabElements.length - 1 ? currentIndex + 1 : 0;
        break;
      case 'Home':
        nextIndex = 0;
        break;
      case 'End':
        nextIndex = tabElements.length - 1;
        break;
      default:
        return;
    }
    e.preventDefault();
    tabElements[nextIndex].focus();
    onTabChange(tabs[nextIndex].id);
  };

  const activeTabLabel = tabs.find(t => t.id === activeTab)?.label || activeTab;

  return (
    <div
      role='tablist'
      style={{ borderBottom: '1px solid var(--border-default)' }}
      aria-label={ariaLabel}
      onKeyDown={handleKeyDown}
    >
      <div className='flex overflow-x-auto'>
        {tabs.map((tab) => {
          const isActive = activeTab === tab.id;
          return (
            <button
              type='button'
              key={tab.id}
              role='tab'
              aria-selected={isActive}
              aria-controls={getTabPanelId(tab.id)}
              tabIndex={isActive ? 0 : -1}
              id={getTabButtonId(tab.id)}
              onClick={() => onTabChange(tab.id)}
              className={cn(
                'relative px-4 py-2.5 text-sm font-medium transition-colors outline-none shrink-0',
                isActive && 'text-text-primary bg-[var(--bg-elevated)]',
                !isActive && 'text-text-muted',
              )}
              onMouseEnter={(e) => {
                if (!isActive) e.currentTarget.style.color = 'var(--text-primary)';
              }}
              onMouseLeave={(e) => {
                if (!isActive) e.currentTarget.style.color = 'var(--text-muted)';
              }}
            >
              <div className='flex items-center gap-2'>
                {tab.label}
                {tab.count !== undefined && tab.count > 0 && (
                  <span
                    className='ml-1 px-1.5 py-0.5 text-xs rounded-sm font-mono'
                    style={{
                      background: 'var(--bg-count-badge)',
                      color: 'var(--text-muted)',
                    }}
                  >
                    {tab.count}
                  </span>
                )}
              </div>
              {isActive && (
                <div
                  className='absolute bottom-0 left-0 right-0 h-0.5'
                  style={{ background: 'var(--accent-blue)' }}
                />
              )}
            </button>
          );
        })}
      </div>
      <div role="status" aria-live="polite" className="sr-only">
        {announcement}
      </div>
    </div>
  );
}

